python3 -c "
import xml.etree.ElementTree as ET
tree = ET.parse('/work/output/artifacts/skill-bpmn-hitl-schema-design/VendorPOReviewBpmn/VendorPOReviewBpmn.bpmn')
root = tree.getroot()
ns = {
  'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
  'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
  'uipath': 'http://uipath.org/schema/bpmn',
}

# Collect all declared ids
all_ids = {el.get('id') for el in root.iter() if el.get('id')}
print('All IDs:', sorted(all_ids))

# Check sequenceFlow refs resolve
errors = []
for sf in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}sequenceFlow'):
  for attr in ('sourceRef','targetRef'):
    v = sf.get(attr)
    if v and v not in all_ids:
      errors.append(f'sequenceFlow {sf.get(\"id\")}: {attr}={v} not found')

# Check incoming/outgoing text refs
for el in root.iter():
  tag = el.tag.split('}')[-1]
  if tag in ('incoming','outgoing'):
    if el.text and el.text.strip() not in all_ids:
      errors.append(f'{tag} ref {el.text.strip()} not found')

# Check BPMNShape bpmnElement refs
for shape in root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNShape'):
  v = shape.get('bpmnElement')
  if v and v not in all_ids:
    errors.append(f'BPMNShape bpmnElement={v} not found')

# Check BPMNEdge bpmnElement refs
for edge in root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNEdge'):
  v = edge.get('bpmnElement')
  if v and v not in all_ids:
    errors.append(f'BPMNEdge bpmnElement={v} not found')

# Exclusive gateway: non-default flows must have conditions, default has none
proc = root.find('{http://www.omg.org/spec/BPMN/20100524/MODEL}process')
flow_map = {}
for sf in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}sequenceFlow'):
  has_cond = sf.find('{http://www.omg.org/spec/BPMN/20100524/MODEL}conditionExpression') is not None
  flow_map[sf.get('id')] = has_cond

for gw in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}exclusiveGateway'):
  default = gw.get('default')
  outgoing = [o.text.strip() for o in gw.findall('{http://www.omg.org/spec/BPMN/20100524/MODEL}outgoing')]
  for fid in outgoing:
    if fid == default and flow_map.get(fid, False):
      errors.append(f'Gateway {gw.get(\"id\")}: default flow {fid} must not have condition')
    elif fid != default and not flow_map.get(fid, False):
      errors.append(f'Gateway {gw.get(\"id\")}: non-default flow {fid} must have condition')

# Check diagram coverage
bpmn_shapes = {s.get('bpmnElement') for s in root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNShape')}
bpmn_edges  = {e.get('bpmnElement') for e in root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNEdge')}
flow_nodes = set()
for el in root.iter():
  tag = el.tag.split('}')[-1]
  if tag in ('startEvent','endEvent','task','userTask','scriptTask','exclusiveGateway','parallelGateway','intermediateCatchEvent'):
    flow_nodes.add(el.get('id'))
flows = {sf.get('id') for sf in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}sequenceFlow')}

for nid in flow_nodes:
  if nid not in bpmn_shapes:
    errors.append(f'Node {nid} has no BPMNShape')
for fid in flows:
  if fid not in bpmn_edges:
    errors.append(f'Flow {fid} has no BPMNEdge')

if errors:
  print('ERRORS:')
  for e in errors: print(' ', e)
else:
  print('VALID - all structural checks passed')
